import java.io.*;

public class CommandInjectionExample {

    public static void main(String[] args) {
        try {
            BufferedReader reader = new BufferedReader(new InputStreamReader(System.in));
            System.out.print("Enter a command to execute: ");
            String command = reader.readLine();

            // Sanitize the input to allow only alphanumeric characters
            if (!command.matches("[a-zA-Z0-9]+")) {
                throw new IllegalArgumentException("Invalid command format");
            }

            // Execute the sanitized command using ProcessBuilder
            Process process = new ProcessBuilder("ping", command).start();

            BufferedReader inputReader = new BufferedReader(new InputStreamReader(process.getInputStream()));
            String inputLine;

            while ((inputLine = inputReader.readLine()) != null) {
                System.out.println(inputLine);
            }
        } catch (IOException e) {
            e.printStackTrace();
        } catch (IllegalArgumentException e) {
            System.err.println(e.getMessage());
        }
    }
}

